export default async function ({ execution_id }) {
  const ex = await fetch(`/platform/automation/v1/executions/${execution_id}`);
  const data = await ex.json();
  const problemTitle = data.params?.event?.['event.name'] || '';
  const affectedEntity = data.params?.event?.['affected_entity_ids']?.[0] || '';

  // Map known EasyTrade services to their feature flags
  const flagMap = {
    'broker': 'high_cpu_usage',
    'credit-card': 'factory_crisis',
    'third-party': 'factory_crisis',
    'offer': 'ergo_aggregator_slowdown',
    'aggregator': 'ergo_aggregator_slowdown',
    'login': 'db_not_responding',
    'account': 'db_not_responding',
    'trade': 'db_not_responding'
  };

  let matchedFlag = null;
  const lowerTitle = problemTitle.toLowerCase();
  for (const [keyword, flag] of Object.entries(flagMap)) {
    if (lowerTitle.includes(keyword) || affectedEntity.toLowerCase().includes(keyword)) {
      matchedFlag = flag;
      break;
    }
  }

  // Default to db_not_responding if no match
  if (!matchedFlag) matchedFlag = 'db_not_responding';

  return { ff_key: matchedFlag, problemTitle, affectedEntity };
}
